import{_ as t,c as r,o as i,ag as n}from"./chunks/framework.By5zrZ8k.js";const d=JSON.parse('{"title":"Hybrid RAG with NetApp","description":"","frontmatter":{},"headers":[],"relativePath":"projects/mlai/rag/hybrid-rag-graph.md","filePath":"projects/mlai/rag/hybrid-rag-graph.md","lastUpdated":1773684674000}'),o={name:"projects/mlai/rag/hybrid-rag-graph.md"};function a(s,e,l,p,g,h){return i(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="hybrid-rag-with-netapp" tabindex="-1">Hybrid RAG with NetApp <a class="header-anchor" href="#hybrid-rag-with-netapp" aria-label="Permalink to &quot;Hybrid RAG with NetApp&quot;">​</a></h1><p><strong>Graph + Vector Retrieval with Governance Built In</strong></p><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>This project highlights a <strong>Hybrid Retrieval-Augmented Generation (Hybrid RAG)</strong> architecture developed and validated by <strong>NetApp</strong>.</p><p>The design combines <strong>GraphRAG</strong> for explicit truth grounding with <strong>vector embeddings</strong> for semantic context. In practice, the system extracts <strong>entities and relationships (triplets)</strong> from source documents into a <strong>Knowledge Graph</strong>, while also storing chunk embeddings for semantic retrieval. The result is a retrieval architecture that balances <strong>governance, explainability, and contextual completeness</strong> without relying on opaque vector similarity alone.</p><p>This page provides a NetApp-focused overview of the architecture and its enterprise implications. The full open source reference implementation lives here: 👉 <strong><a href="https://github.com/NetApp/hybrid-rag-graph-with-ai-governance" target="_blank" rel="noreferrer">https://github.com/NetApp/hybrid-rag-graph-with-ai-governance</a></strong></p><h2 id="_2-why-hybrid-rag" tabindex="-1">2. Why Hybrid RAG <a class="header-anchor" href="#_2-why-hybrid-rag" aria-label="Permalink to &quot;2. Why Hybrid RAG&quot;">​</a></h2><p>Pure vector RAG is good at &quot;semantic vibes&quot; but weak at answering hard questions like:</p><ul><li>Why did this result match?</li><li>Which facts actually grounded the answer?</li><li>Can we reproduce this result next week?</li><li>Can we defend it to auditors?</li></ul><p>Graph-based Hybrid RAG addresses those gaps by <strong>grounding retrieval in a Knowledge Graph first</strong>, then using vectors as <strong>supporting semantic context</strong>, not the source of truth.</p><p><img src="https://raw.githubusercontent.com/NetApp/hybrid-rag-graph-with-ai-governance/main/images/rag-hybrid-graph.png" alt="Hybrid RAG with Graph Truth Grounding"></p><p>Key reasons Graph-based Hybrid RAG works:</p><ul><li><p><strong>Deterministic fact traceability</strong>: facts are grounded as explicit entities and relationships rather than inferred only from similarity scores.</p></li><li><p><strong>Audit-ready provenance</strong>: triplets, nodes, and edges can carry source lineage and metadata so evidence remains inspectable.</p></li><li><p><strong>Reduced semantic drift</strong>: the graph constrains grounding to extracted relationships, while vectors add supporting narrative context.</p></li><li><p><strong>Operational explainability</strong>: retrieval can be shown as a subgraph of entities, edges, chunks, and metadata rather than as opaque ANN rankings.</p></li><li><p><strong>Contextual completeness</strong>: vectors still help retrieve surrounding detail and nuance so answers are not limited to terse graph facts.</p></li></ul><p>This architecture also uses explicit <strong>HOT</strong> and <strong>Long-Term (LT)</strong> memory tiers. New or unverified facts can live in HOT memory first, while promotion into LT memory is treated as a controlled event driven by reinforcement or trusted human validation.</p><h2 id="_3-how-netapp-enhances-this-architecture" tabindex="-1">3. How NetApp Enhances This Architecture <a class="header-anchor" href="#_3-how-netapp-enhances-this-architecture" aria-label="Permalink to &quot;3. How NetApp Enhances This Architecture&quot;">​</a></h2><p>NetApp extends Graph-based Hybrid RAG with an <strong>enterprise storage overlay</strong> that makes the design operational at scale.</p><p>Key NetApp contributions include:</p><ul><li><p><strong>Dual-tier graph truth store</strong></p><ul><li><strong>Long-Term (LT)</strong>: authoritative Neo4j graph store for curated document, chunk, and entity evidence</li><li><strong>HOT</strong>: low-latency Neo4j working set for new, user-specific, or unvetted graph evidence</li><li><strong>Vector context store</strong>: OpenSearch for semantic chunk retrieval alongside graph grounding</li></ul></li><li><p><strong>Long-term durability and cost optimization</strong></p><ul><li><strong>FabricPool / auto-tiering</strong> helps move colder Neo4j and OpenSearch data to lower-cost tiers while keeping retrieval transparent</li><li><strong>NetApp XCP</strong> supports large-scale ingestion from legacy HDFS/NFS sources with integrity verification</li></ul></li><li><p><strong>Low-latency HOT operations</strong></p><ul><li><strong>FlexCache</strong> keeps the active HOT graph working set close to inference compute</li><li><strong>Storage QoS</strong> protects HOT query/update paths from noisy-neighbor ingest and rebuild workloads</li><li><strong>FlexClone</strong> enables safe rebuild, migration, and test workflows without destabilizing production HOT memory</li></ul></li><li><p><strong>Enterprise resilience and compliance</strong></p><ul><li><strong>MetroCluster</strong> protects Long-Term graph and vector stores with synchronous replication and zero-RPO posture</li><li><strong>SnapCenter</strong> captures application-consistent snapshots of Neo4j and OpenSearch state</li><li><strong>SnapLock</strong> adds WORM protection for environments that require immutable evidence and audit trails</li></ul></li><li><p><strong>Safe experimentation</strong></p><ul><li>FlexClone allows instant, space-efficient copies of indices for testing new analyzers or embedding models without touching production</li></ul></li></ul><p>NetApp&#39;s role is not to change how Graph + Vector Hybrid RAG works logically, but to <strong>make it reliable, governable, compliant, and operable in real enterprise environments</strong>.</p><h2 id="_4-visit-the-github-project-for-more-details" tabindex="-1">4. Visit the GitHub Project for More Details <a class="header-anchor" href="#_4-visit-the-github-project-for-more-details" aria-label="Permalink to &quot;4. Visit the GitHub Project for More Details&quot;">​</a></h2><p>This page is intentionally concise.</p><p>For full technical details, code, and deployment guidance, visit the open source project:</p><p>👉 <strong><a href="https://github.com/NetApp/hybrid-rag-graph-with-ai-governance" target="_blank" rel="noreferrer">https://github.com/NetApp/hybrid-rag-graph-with-ai-governance</a></strong></p><p>There you&#39;ll find:</p><ul><li>A complete <strong>Graph + Vector Hybrid RAG</strong> reference implementation</li><li>Separate <strong>community</strong> and <strong>enterprise</strong> deployment paths</li><li>Supporting guides for <strong>Hybrid Graph Search for Better AI Governance</strong>, the <strong>Community Version</strong>, and the <strong>Enterprise Version</strong></li><li>Detailed explanations of <strong>truth grounding</strong>, <strong>vector support</strong>, and <strong>HOT/LT operational workflows</strong></li></ul><p>If you&#39;re building RAG systems that need to be <strong>accurate, explainable, and defensible</strong>, that repository is the place to start.</p>',26)])])}const u=t(o,[["render",a]]);export{d as __pageData,u as default};
